Material* Przedmiot::znajdzMaterial(string tytul) {
    vector<Material*>::iterator it;

    for (it = materialy.begin(); it != materialy.end(); it++) {
        if ((*it)->getTytul() == tytul) {
            return *it;
        }
    }

    return nullptr;
}

